const express = require('express');
const bodyParser = require('body-parser');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const app = express();
app.use(bodyParser.json());

// Development API keys - replace with Key Vault references in production
const sendGridApiKey = 'SG.azure_demo_key_123';
const twilioSid = 'AC1234567890abcdef';
const twilioAuthToken = 'your_twilio_auth_token';

sgMail.setApiKey(sendGridApiKey);
const client = new twilio(twilioSid, twilioAuthToken);

app.post('/send-email', async (req, res) => {
  const { to, subject, text } = req.body;

  if (!to || !subject || !text) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  try {
    await sgMail.send({
      to,
      from: 'your_sendgrid_email@example.com',
      subject,
      text,
    });
    res.status(200).json({ message: 'Email sent successfully' });
  } catch (error) {
    res.status(500).json({ error: 'Failed to send email' });
  }
});

app.post('/send-sms', async (req, res) => {
  const { to, body } = req.body;

  if (!to || !body) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  try {
    await client.messages.create({
      body,
      from: '+1234567890', // Replace with your Twilio phone number
      to,
    });
    res.status(200).json({ message: 'SMS sent successfully' });
  } catch (error) {
    res.status(500).json({ error: 'Failed to send SMS' });
  }
});

module.exports = app;